const WebSocket = require('ws');

async function main() {
  // Get the CDP websocket URL
  const http = require('http');
  const res = await new Promise((resolve, reject) => {
    http.get('http://172.18.0.3:50219/json', (r) => {
      let data = '';
      r.on('data', chunk => data += chunk);
      r.on('end', () => resolve(JSON.parse(data)));
    }).on('error', reject);
  });

  const page = res.find(t => t.type === 'page');
  if (!page) { console.error('No page found'); process.exit(1); }

  const ws = new WebSocket(page.webSocketDebuggerUrl);
  let id = 1;
  const send = (method, params = {}) => new Promise((resolve) => {
    const msgId = id++;
    ws.send(JSON.stringify({ id: msgId, method, params }));
    ws.on('message', function handler(data) {
      const msg = JSON.parse(data);
      if (msg.id === msgId) { ws.removeListener('message', handler); resolve(msg); }
    });
  });

  await new Promise(r => ws.on('open', r));

  // Get the document
  const { result: { root: { nodeId: docId } } } = await send('DOM.getDocument');

  // Find the country select element
  const { result: { nodeIds } } = await send('DOM.querySelectorAll', { nodeId: docId, selector: 'select[name="Country"]' });

  if (nodeIds.length === 0) {
    // Try another selector
    const { result: { nodeIds: nodeIds2 } } = await send('DOM.querySelectorAll', { nodeId: docId, selector: 'select' });
    console.log('Found select elements:', nodeIds2.length);
    for (const nid of nodeIds2) {
      const { result: { outerHTML } } = await send('DOM.getOuterHTML', { nodeId: nid });
      console.log(outerHTML.substring(0, 200));
    }
  } else {
    console.log('Found Country select, nodeId:', nodeIds[0]);
  }

  // Use Runtime.evaluate to change the value
  const evalResult = await send('Runtime.evaluate', {
    expression: `
      (function() {
        const selects = document.querySelectorAll('select');
        let result = [];
        for (const s of selects) {
          result.push(s.name || s.id || s.getAttribute('aria-label') || 'unnamed');
        }
        return JSON.stringify(result);
      })()
    `
  });
  console.log('Selects found:', evalResult.result?.result?.value);

  ws.close();
}

main().catch(console.error);
